mapper.select:
SELECT e.id, e.student_id, e.subject_id, e.semester, s.name AS student_name, sub.subject_name FROM enrollment e LEFT JOIN student s ON e.student_id = s.id LEFT JOIN subject sub ON e.subject_id = sub.id WHERE e.student_id = #{studentId}
AND e.semester = #{semester}
ORDER BY sub.subject_name
